CODE_EXAMPLE:
// Before
int discount(int inputVal, int quantity) {
  if (inputVal > 50) {
    inputVal -= 2;
  }
  return inputVal * quantity;
}

// After
int discount(int inputVal, int quantity) {
  int result = inputVal;
  if (inputVal > 50) {
    result -= 2;
  }
  return result * quantity;
}

UNIT_TEST_EXAMPLE:
@Test
public void testRemoveParameterAssignment() {
  assertEquals(98, discount(100, 1));
  assertEquals(150, discount(30, 5));
}
